#include <iostream>

class IntBuffer
{
    int* m_data{};
    int m_size{};

public:
    IntBuffer(int size)
        : m_data{ new int[size]{} }, m_size{ size }
    {
        std::cout << "acquired " << m_size << '\n';
    }

    ~IntBuffer()
    {
        std::cout << "released " << m_size << '\n';
        delete[] m_data;
    }

    void set(int index, int value) { m_data[index] = value; }

    int sum() const
    {
        int total{ 0 };
        for (int i{ 0 }; i < m_size; ++i)
