#include <iostream>

struct OwnedArray
{
    int* data{};
    int size{};
};

OwnedArray runningSums(const int* src, int n)
{
    int* out{ new int[n]{} };
    int acc{ 0 };
    for (int i{ 0 }; i < n; ++i)
    {
        acc += src[i];
        out[i] = acc;
    }
    return OwnedArray{ out, n };
}

int main()
{
    int n{};
    std::cin >> n;

    int* input{ new int[n]{} };
    for (int i{ 0 }; i < n; ++i)
        std::cin >> input[i];

    OwnedArray result{ runningSums(input, n) };
    delete[] input;

    for (int i{ 0 }; i < result.size; ++i)
    {
        if (i > 0)
            std::cout << ' ';
        std::cout << result.data[i];
    }
    std::cout << '\n';

    delete[] result.data;
    std::cout << "cleaned up" << '\n';

    return 0;
}
